import SmilesDrawer from 'https://cdn.jsdelivr.net/npm/smiles-drawer@2/+esm';
const canvas = document.createElement('canvas');
canvas.width = data.width ?? 480; canvas.height = data.height ?? 320;
document.getElementById('molecule').appendChild(canvas);
const drawer = new SmilesDrawer.Drawer({ width: canvas.width, height: canvas.height });
SmilesDrawer.parse(data.smiles, tree => drawer.draw(tree, canvas, data.theme ?? 'light', false), err => { throw err; });

